INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.9.187','cb','cb.adi.9','ЧБ Ади 9.187',187,'এইমত মাধবেন্দ্র নিত্যানন্দ-প্রতি ।
অহর্নিশ বোলেন, করেন রতি-মতি ॥১৮৭॥','эи-мата ма̄дхавендра нитйа̄нанда-прати
ахар-ниш́а болена, карена рати-мати',NULL,NULL),('cb.adi.9.188','cb','cb.adi.9','ЧБ Ади 9.188',188,'মাধবেন্দ্র-প্রতি নিত্যানন্দ মহাশয় ।
গুরু-বুদ্ধি ব্যতিরিক্ত আর না করয় ॥১৮৮॥','ма̄дхавендра-прати нитйа̄нанда маха̄ш́айа
гуру-буддхи вйатирикта а̄ра на̄ карайа',NULL,NULL),('cb.adi.9.189','cb','cb.adi.9','ЧБ Ади 9.189',189,'এইমত অন্যোঽন্যে দুই মহামতি ।
কৃষ্ণপ্রেমে না জানেন কোথা দিবা-রাতি ॥১৮৯॥','эи-мата анйо ‘нйе дуи маха̄мати
кр̣ш̣н̣а-преме на̄ джа̄нена котха̄ дива̄-ра̄ти',NULL,NULL),('cb.adi.9.190','cb','cb.adi.9','ЧБ Ади 9.190',190,'কতদিন মাধবেন্দ্র-সঙ্গে নিত্যানন্দ ।
থাকিয়া চলিলা শেষে যথা সেতুবন্ধ ॥১৯০॥','ката-дина ма̄дхавендра-сан̇ге нитйа̄нанда
тха̄кийа̄ чалила̄ ш́еш̣е йатха̄ сетубендха',NULL,NULL),('cb.adi.9.191','cb','cb.adi.9','ЧБ Ади 9.191',191,'মাধবেন্দ্র চলিলা সরযূ দেখিবারে ।
কৃষ্ণাবেশে কেহ নিজ-দেহ নাহি স্মরে ॥১৯১॥','ма̄дхавендра чалила̄ сарайӯ декхиба̄ре
кр̣ш̣н̣а̄веш́е кеха ниджа-деха на̄хи смаре',NULL,NULL),('cb.adi.9.192','cb','cb.adi.9','ЧБ Ади 9.192',192,'অতএব জীবনের রক্ষা সে-বিরহে ।
বাহ্য থাকিলে কি সে-বিরহে প্রাণ রহে? ॥১৯২॥','атаева джӣванера ракш̣а̄ се-вихаре
ба̄хйа тха̄киле ки се-вихаре пра̄н̣а рахе?',NULL,NULL),('cb.adi.9.193','cb','cb.adi.9','ЧБ Ади 9.193',193,'নিত্যানন্দ-মাধবেন্দ্র, দুই-দরশন ।
যে শুনয়ে, তারে মিলে কৃষ্ণপ্রেম-ধন ॥১৯৩॥','нитйа̄нанда-ма̄дхавендра, дуи-дараш́ана
йе ш́унайе, та̄’ре миле кр̣ш̣н̣а-према-дхана',NULL,NULL),('cb.adi.9.194','cb','cb.adi.9','ЧБ Ади 9.194',194,'হেনমতে নিত্যানন্দ ভ্রমে’ প্রেমরসে ।
সেতুবন্ধে আইলেন কতেক দিবসে ॥১৯৪॥','хена-мате нитйа̄нанда бхраме’ према-расе
сетубандхе а̄илена катека дивасе',NULL,NULL),('cb.adi.9.195','cb','cb.adi.9','ЧБ Ади 9.195',195,'ধনুতীর্থে স্নান করি’ গেলা রামেশ্বর ।
তবে প্রভু আইলেন বিজয়নগর ॥১৯৫॥','дхану-тӣртхе сна̄на кари’ гела̄ ра̄меш́вара
табе прабху а̄илена виджайанагара',NULL,NULL),('cb.adi.9.196','cb','cb.adi.9','ЧБ Ади 9.196',196,'মায়াপুরী, অবন্তী দেখিয়া গোদাবরী ।
আইলেন জিওড়-নৃসিংহদেবপুরী ॥১৯৬॥','ма̄йа̄пурӣ авантӣ декхийа̄ года̄варӣ
а̄илена джиод̣а-нр̣сим̇хадева-пурӣ',NULL,NULL),('cb.adi.9.197','cb','cb.adi.9','ЧБ Ади 9.197',197,'ত্রিমল্ল দেখিয়া কূর্ম্মনাথ পুণ্যস্থান ।
শেষে নীলাচলচন্দ্র দেখিতে পয়ান ॥১৯৭॥','тримала декхийа̄ кӯрма-на̄тха пун̣йа-стха̄на
ш́еш̣е нӣла̄чалачандра декхите пайа̄на',NULL,NULL),('cb.adi.9.198','cb','cb.adi.9','ЧБ Ади 9.198',198,'আইলেন নীলাচলচন্দ্রের নগরে ।
ধ্বজ দেখি’ মাত্র মূর্চ্ছা হইল শরীরে ॥১৯৮॥','а̄илена нӣла̄чалачандрера нагаре
дхваджа декхи’ ма̄тра мӯрчха̄ хаила ш́арӣре',NULL,NULL),('cb.adi.9.199','cb','cb.adi.9','ЧБ Ади 9.199',199,'দেখিলেন চতূর্ব্ব্যূহ-রূপ জগন্নাথ ।
প্রকট পরমানন্দ ভক্তবর্গ-সাথ ॥১৯৯॥','декхилена чатур-вйӯха-рӯпа джаганна̄тха
пракат̣а парама̄нанда бхакта-варга-са̄тха',NULL,NULL),('cb.adi.9.200','cb','cb.adi.9','ЧБ Ади 9.200',200,'দেখি’ মাত্র হইলেন পুলকে মূর্চ্ছিতে ।
পুনঃ বাহ্য হয়, পুনঃ পড়ে পৃথিবীতে ॥২০০॥','декхи’ ма̄тра хаилена пулаке мӯрчхите
пунах̣ ба̄хйа хайа, пунах̣ пад̣е пр̣тхивӣте',NULL,NULL),('cb.adi.9.201','cb','cb.adi.9','ЧБ Ади 9.201',201,'কম্প, স্বেদ, পুলকাশ্রু, আছাড়, হুঙ্কার ।
কে কহিতে পারে নিত্যানন্দের বিকার ? ॥২০১॥','кампа, сведа пулака̄ш́ру, а̄чха̄д̣а, хун̇ка̄ра
ке кахите па̄ре нитйа̄нандера вика̄ра?',NULL,NULL),('cb.adi.9.202','cb','cb.adi.9','ЧБ Ади 9.202',202,'এইমত নিত্যানন্দ থাকি’ নীলাচলে ।
দেখি’ গঙ্গাসাগর আইলা কুতূহলে ॥২০২॥','эи-мата нитйа̄нанда тха̄ки’ нӣла̄чале
декхи, ган̇га̄-са̄гара а̄ила̄ кутухале',NULL,NULL),('cb.adi.9.203','cb','cb.adi.9','ЧБ Ади 9.203',203,'তাঁর তীর্থযাত্রা সব কে পারে কহিতে? ।
কিছু লিখিলাঙ মাত্র তাঁর কৃপা হৈতে ॥২০৩॥','та̄н̇’ра тӣртха-йа̄тра̄ саба ке па̄ре кахите?
кичху ликхила̄н̇а ма̄тра та̄н̇’ра кр̣па̄ хаите',NULL,NULL),('cb.adi.9.204','cb','cb.adi.9','ЧБ Ади 9.204',204,'এইমত তীর্থ ভ্রমি’ নিত্যানন্দ-রায় ।
পুনর্ব্বার আসিয়া মিলিলা মথুরায় ॥২০৪॥','эи-мата тӣртха бхрами’ нитйа̄нанда-ра̄йа
пунар-ба̄ра а̄сийа̄ милита̄ матхура̄йа',NULL,NULL),('cb.adi.9.205','cb','cb.adi.9','ЧБ Ади 9.205',205,'নিরবধি বৃন্দাবনে করেন বসতি ।
কৃষ্ণের আবেশে না জানেন দিবা-রাতি ॥২০৫॥','ниравадхи вр̣нда̄ване карена васати
кр̣ш̣н̣ера а̄веш́е на̄ джа̄нера дива̄-ра̄ти',NULL,NULL),('cb.adi.9.206','cb','cb.adi.9','ЧБ Ади 9.206',206,'আহার নাহিক, কদাচিৎ দুগ্ধ-পান ।
সেহ যদি অযাচিত কেহ করে দান ॥২০৬॥','а̄ха̄ра на̄хика, када̄чит дугдха-па̄на
сеха йади айа̄чита кеха каре да̄на',NULL,NULL),('cb.adi.9.207','cb','cb.adi.9','ЧБ Ади 9.207',207,'নবদ্বীপে গৌরচন্দ্র আছে গুপ্তভাবে ।
ইহা নিত্যানন্দস্বরূপের মনে জাগে ॥২০৭॥','навадвӣпе гаурачандра а̄чхе гупта-бха̄ве
иха̄ нитйа̄нанда-сварӯпера мане джа̄ге',NULL,NULL),('cb.adi.9.208','cb','cb.adi.9','ЧБ Ади 9.208',208,'“আপন-ঐশ্বর্য্য প্রভু প্রকাশিবে যবে ।
আমি গিয়া করিমু আপন সেবা তবে” ॥২০৮॥','‘а̄пана-аиш́варйа прабху прака̄ш́ибе йабе
а̄ми гийа̄ кариму а̄пана сева̄ табе’',NULL,NULL),('cb.adi.9.209','cb','cb.adi.9','ЧБ Ади 9.209',209,'এই মানসিক করি’ নিত্যানন্দ-রায় ।
মথুরা ছাড়িয়া নবদ্বীপে নাহি যায় ॥২০৯॥','эи ма̄насика кари’ нитйа̄нанда-ра̄йа
матхура̄ чха̄д̣ийа̄ навадвӣпа на̄хи йа̄йа',NULL,NULL),('cb.adi.9.210','cb','cb.adi.9','ЧБ Ади 9.210',210,'নিরবধি বিহরয়ে কালিন্দীর জলে ।
শিশু-সঙ্গে বৃন্দাবনে ধূলা-খেলা খেলে ॥২১০॥
যদ্যপিহ নিত্যানন্দ ধরে সর্ব্ব শক্তি ।
তথাপিহ কারেহ না দিলেন বিষ্ণুভক্তি ॥২১১॥
যবে গৌরচন্দ্র প্রভু করিবে প্রকাশ ।
তান সে আজ্ঞায় ভক্তিদানের বিলাস ॥২১২॥
কেহ কিছু না করে চৈতন্য-আজ্ঞা বিনে ।
ইহাতে ‘অল্পতা’ নাহি পায় প্রভু-গণে ॥২১৩॥','ниравадхи вихарайе ка̄линдӣра джале
ш́иш́у-сан̇ге вр̣нда̄ване дхӯла̄ кхела̄ кхеле
йадйа̄пиха нитйа̄нанда дхаре сарва ш́акти
татха̄пиха ка̄’реха на̄ дилена виш̣н̣у-бхакти
йабе гаурачандра прабху карибе прака̄ш́а
та̄’на се а̄джн̃а̄йа бхакти-да̄нера вила̄са
кеха кичху на̄ каре чаитанйа-а̄джн̃а̄ вине
иха̄те ‘алпата̄’ на̄хи па̄йа прабху-ган̣е',NULL,NULL),('cb.adi.9.214','cb','cb.adi.9','ЧБ Ади 9.214',214,'কি অনন্ত, কিবা শিব-অজাদি দেবতা ।
চৈতন্য-আজ্ঞায় হর্ত্তা-কর্ত্তা পালয়িতা ॥২১৪॥','ки ананта, киба̄ ш́ива-аджа̄ди девата̄
чаитанйа-а̄джн̃а̄йа харта̄-карта̄ па̄лайита̄',NULL,NULL),('cb.adi.9.215','cb','cb.adi.9','ЧБ Ади 9.215',215,'ইহাতে যে পাপীগণ মনে দুঃখ পায় ।
বৈষ্ণবের অদৃশ্য সে পাপী সর্ব্বথায় ॥২১৫॥','иха̄те йе па̄пӣ-ган̣а мане дух̣кха па̄йа
ваиш̣н̣авера адр̣ш́йа се па̄пӣ сарватха̄йа',NULL,NULL),('cb.adi.9.216','cb','cb.adi.9','ЧБ Ади 9.216',216,'সাক্ষাতেই দেখ সবে এই ত্রিভুবনে ।
নিত্যানন্দ-দ্বারে পাইলেন প্রেমধনে ॥২১৬॥','са̄кш̣а̄теи декха сабе эи трибхуване
нитйа̄нанда-два̄ре па̄илена према-дхане',NULL,NULL),('cb.adi.9.217','cb','cb.adi.9','ЧБ Ади 9.217',217,'চৈতন্যের আদি-ভক্ত নিত্যানন্দ-রায় ।
চৈতন্যের যশ বৈসে যাঁহার জিহ্বায় ॥২১৭॥','чаитанйера а̄ди-бхакта нитйа̄нанда-ра̄йа
чаитанйера йаш́а ваисе йа̄н̇ха̄ра джихва̄йа',NULL,NULL),('cb.adi.9.218','cb','cb.adi.9','ЧБ Ади 9.218',218,'অহর্নিশ চৈতন্যের কথা প্রভু কয় ।
তাঁরে ভজিলে সে চৈতন্যভক্তি হয় ॥২১৮॥','ахар-ниш́а чаитанйера катха̄ прабху кайа
та̄н̇’ре бхаджиле се чаитанйа-бхакти хайа',NULL,NULL),('cb.adi.9.219','cb','cb.adi.9','ЧБ Ади 9.219',219,'আদিদেব জয় জয় নিত্যানন্দ-রায় ।
চৈতন্য-মহিমা স্ফুরে যাঁহার কৃপায় ॥২১৯॥','а̄ди-дева джайа джайа нитйа̄нанда-ра̄йа
чаитанйа-махима̄ спхуре йа̄н̇ха̄ра кр̣па̄йа',NULL,NULL),('cb.adi.9.220','cb','cb.adi.9','ЧБ Ади 9.220',220,'চৈতন্য-কৃপায় হয় নিত্যানন্দে রতি ।
নিত্যানন্দে জানিলে আপদ্ নাহি কতি ॥২২০॥','чаитанйа-кр̣па̄йа хайа нитйа̄нанде рати
нитйа̄нанде джа̄ниле а̄пад на̄хи кати',NULL,NULL),('cb.adi.9.221','cb','cb.adi.9','ЧБ Ади 9.221',221,'সংসারের পার হঞা ভক্তির সাগরে ।
যে ডুবিবে, সে ভজুক নিতাইচান্দেরে ॥২২১॥','сам̇са̄рера па̄ра хан̃а̄ бхактира са̄гаре
йе д̣убибе, се бхаджука нита̄ича̄ндере',NULL,NULL),('cb.adi.9.222','cb','cb.adi.9','ЧБ Ади 9.222',222,'কেহ বোলে,—“নিত্যানন্দ যেন বলরাম” ।
কেহ বোলে,—“চৈতন্যের বড় প্রিয়ধাম” ॥২২২॥
কিবা যতি নিত্যানন্দ, কিবা ভক্ত জ্ঞানী ।
যার যেন মত ইচ্ছা, না বোলয়ে কেনি ॥২২৩॥
যে-সে কেনে চৈতন্যের নিত্যানন্দ নহে ।
তবু সেই পাদপদ্ম রহুক হৃদয়ে ॥২২৪॥','кеха боле, — ‘нитйа̄нанда йена балара̄ма’
кеха боле, — ‘чаитанйера бад̣а прийа-дха̄ма’
киба̄ йати нитйа̄нанда, киба̄ бхакта джн̃а̄нӣ
йа̄’ра йена мата иччха̄, на̄ болайе кени
йе-се кене чаитанйера нитйа̄нанда нахе
табу сеи па̄да-падма рахука хр̣дайе',NULL,NULL),('cb.adi.9.225','cb','cb.adi.9','ЧБ Ади 9.225',225,'এত পরিহারেও যে পাপী নিন্দা করে ।
তবে লাথি মারোঁ তার শিরের উপরে ॥২২৫॥','эта париха̄ре о йе па̄пӣ нинда̄ каре
табе ла̄тхи ма̄рон̇ та̄’ра ш́ирера упаре',NULL,NULL),('cb.adi.9.226','cb','cb.adi.9','ЧБ Ади 9.226',226,'কোন চৈতন্যের লোক নিত্যানন্দ-প্রতি ।
